import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.DIMps2S2.js";const m=JSON.parse('{"title":"MT103 汇款回执","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"deposit/mt103-receipt.md","filePath":"zh-CN/deposit/mt103-receipt.md"}'),o={name:"deposit/mt103-receipt.md"};function i(l,t,h,n,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="mt103-汇款回执" tabindex="-1">MT103 汇款回执 <a class="header-anchor" href="#mt103-汇款回执" aria-label="Permalink to &quot;MT103 汇款回执&quot;">​</a></h1><p>MT103 国际电汇报文格式、关键字段说明及手续费承担方式，用于追踪电汇入金进度。</p><h2 id="什么是-mt103" tabindex="-1">什么是 MT103 <a class="header-anchor" href="#什么是-mt103" aria-label="Permalink to &quot;什么是 MT103&quot;">​</a></h2><p>MT103 是国际银行间通用的电汇报文格式，用于记录和传递跨行转账信息。只要有电汇转账就会生成 MT103 报文，在银行系统内部流转。当电汇入金到账较慢时，可向汇款银行索取 MT103 报文，用于追踪汇款进度。</p><h2 id="电汇路径" tabindex="-1">电汇路径 <a class="header-anchor" href="#电汇路径" aria-label="Permalink to &quot;电汇路径&quot;">​</a></h2><h3 id="香港境内汇款" tabindex="-1">香港境内汇款 <a class="header-anchor" href="#香港境内汇款" aria-label="Permalink to &quot;香港境内汇款&quot;">​</a></h3><p>客户银行（发出行）发送 MT103 报文 → 长桥收款银行（收款行）收到报文并匹配信息 → 长桥分配资金到客户账户。</p><h3 id="国际跨境汇款" tabindex="-1">国际跨境汇款 <a class="header-anchor" href="#国际跨境汇款" aria-label="Permalink to &quot;国际跨境汇款&quot;">​</a></h3><p>客户银行（发出行）发送 MT103 报文 → 中转行 1（与发出行合作的国际大行）→ 中转行 2（与收款行合作）→ 长桥收款银行（收款行）匹配信息 → 长桥分配资金到客户账户。</p><p>注意：中转行不限于 1-2 家，如双方合作银行之间无法直接传送报文，可能存在更多中转行，这也是跨境电汇耗时较长的原因。</p><h2 id="mt103汇款回执关键字段" tabindex="-1">MT103汇款回执关键字段 <a class="header-anchor" href="#mt103汇款回执关键字段" aria-label="Permalink to &quot;MT103汇款回执关键字段&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>名称</th><th>用途</th></tr></thead><tbody><tr><td>20</td><td>汇款银行编号</td><td>用于查询实际汇款行</td></tr><tr><td>32A</td><td>汇款时间和金额</td><td>核实发出时间、币种和金额（发出行扣除手续费后的已结算金额）</td></tr><tr><td>50K</td><td>汇款方信息</td><td>核实汇款方名称和地址</td></tr><tr><td>56A</td><td>收款方银行代理行</td><td>查看代理行和中间行信息，包括 SWIFT/BIC 代码</td></tr><tr><td>57A</td><td>收款方银行</td><td>核实收款方银行信息，包括 SWIFT/BIC 代码和名称</td></tr><tr><td>59</td><td>收款方信息</td><td>核实收款方名称和地址</td></tr><tr><td>70</td><td>汇款附言</td><td>汇款方填写的备注信息</td></tr><tr><td>71A</td><td>手续费承担方式</td><td>SHA = 共同承担（默认），BEN = 收款方承担，OUR = 汇款方承担</td></tr></tbody></table><p>SWIFT 代码统一为 11 位数，位数不够时系统会用「XXX」补齐，对汇款无影响。</p><h2 id="手续费承担方式说明" tabindex="-1">手续费承担方式说明 <a class="header-anchor" href="#手续费承担方式说明" aria-label="Permalink to &quot;手续费承担方式说明&quot;">​</a></h2><ul><li><strong>SHA</strong>（共同承担）：一般默认选项，后程费用基本由收款方承担</li><li><strong>BEN</strong>（收款方承担）：所有手续费由收款方承担</li><li><strong>OUR</strong>（汇款方承担）：汇款方承担大部分费用</li></ul><h2 id="如何使用-mt103" tabindex="-1">如何使用 MT103 <a class="header-anchor" href="#如何使用-mt103" aria-label="Permalink to &quot;如何使用 MT103&quot;">​</a></h2><p>如电汇入金长时间未到账，可联系汇款银行索取 MT103 报文，并提供给长桥客服协助追踪资金状态。</p><h2 id="引用此页面的文档" tabindex="-1">引用此页面的文档 <a class="header-anchor" href="#引用此页面的文档" aria-label="Permalink to &quot;引用此页面的文档&quot;">​</a></h2><ul><li><a href="/wiki/deposit">入金</a></li></ul>',19)])])}const u=a(o,[["render",i]]);export{m as __pageData,u as default};
